definition.script:
pipeline {
    agent any
    stages {
        stage('Clone') {
            steps {
                git branch: 'main',
                credentialsId: 'github-credentials',
                url: 'https://github.com/Prasanth102/ai-devops-log-analyzer.git'
            }
        }
        stage('Build') {
            steps {
                sh 'echo Building...'
                sh 'pip install -r requirements.txt --break-system-packages'
            }
        }
        stage('Test') {
            steps {
                sh 'echo Testing...'
            }
        }
        stage('Deploy') {
            steps {
                sh 'echo Deploying successfully!'
            }
        }
    }
}
